import{_ as t,o as r,c as l,ae as o}from"./chunks/framework.Czhw_PXq.js";const g=JSON.parse('{"title":"《黑天鹅》深度解读系列（二）：两个世界——平均斯坦与极端斯坦","description":"深入理解塔勒布的核心框架：平均斯坦与极端斯坦的本质区别，为什么现代社会越来越多地进入极端斯坦，以及这个区分对我们理解世界的重要性","frontmatter":{"title":"《黑天鹅》深度解读系列（二）：两个世界——平均斯坦与极端斯坦","description":"深入理解塔勒布的核心框架：平均斯坦与极端斯坦的本质区别，为什么现代社会越来越多地进入极端斯坦，以及这个区分对我们理解世界的重要性","pubDate":"2026-04-18","heroImage":"/images/black-swan-new/table_image_56_0.jpg","tags":["黑天鹅","塔勒布","平均斯坦","极端斯坦","不确定性"]},"headers":[],"relativePath":"posts/black-swan-part2.md","filePath":"posts/black-swan-part2.md"}'),i={name:"posts/black-swan-part2.md"};function e(n,a,s,h,p,d){return r(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="《黑天鹅》深度解读系列-二-两个世界——平均斯坦与极端斯坦" tabindex="-1">《黑天鹅》深度解读系列（二）：两个世界——平均斯坦与极端斯坦 <a class="header-anchor" href="#《黑天鹅》深度解读系列-二-两个世界——平均斯坦与极端斯坦" aria-label="Permalink to &quot;《黑天鹅》深度解读系列（二）：两个世界——平均斯坦与极端斯坦&quot;">​</a></h1><blockquote><p>&quot;在理想的平均斯坦，特定事件的单独影响很小，只有群体影响才大；在极端斯坦，个体能够对整体产生不成比例的影响。极端斯坦能够制造黑天鹅现象，少数事件已经对历史产生了巨大影响。&quot;</p></blockquote><h2 id="一、引言-为什么需要区分两个世界" tabindex="-1">一、引言：为什么需要区分两个世界？ <a class="header-anchor" href="#一、引言-为什么需要区分两个世界" aria-label="Permalink to &quot;一、引言：为什么需要区分两个世界？&quot;">​</a></h2><p>在《黑天鹅》中，纳西姆·塔勒布提出了一个革命性的概念框架，用以理解我们生活在一个怎样的世界中。这个框架将世界分为两个截然不同的领域：<strong>平均斯坦（Mediocristan）<strong>和</strong>极端斯坦（Extremistan）</strong>。</p><p>这个区分之所以重要，是因为它揭示了为什么传统的统计学方法、预测模型和风险管理工具在现代社会中越来越失效。如果我们不理解自己生活在哪个&quot;斯坦&quot;中，我们就会用错误的工具去理解世界，从而陷入危险的错觉。</p><p>塔勒布在书中写道：&quot;把左右两栏混淆将导致可怕（或极端走运）的结果。&quot;这正是2008年金融危机的根源——金融工程师们用平均斯坦的工具去管理极端斯坦的风险。</p><h2 id="二、平均斯坦-温和的世界" tabindex="-1">二、平均斯坦：温和的世界 <a class="header-anchor" href="#二、平均斯坦-温和的世界" aria-label="Permalink to &quot;二、平均斯坦：温和的世界&quot;">​</a></h2><h3 id="定义与特征" tabindex="-1">定义与特征 <a class="header-anchor" href="#定义与特征" aria-label="Permalink to &quot;定义与特征&quot;">​</a></h3><p>平均斯坦是一个受<strong>温和随机性</strong>支配的世界。在这个世界中，个体事件的影响是有限的，整体由大量小事件组成，极端事件极其罕见，即使发生也不会对整体产生重大影响。</p><p>平均斯坦的核心特征是<strong>非突破性</strong>。这意味着：</p><ul><li>个体事件的影响有明确的上限</li><li>极端事件极其罕见</li><li>大数定律有效：样本越大，平均值越稳定</li><li>单一观察值不会决定整体结果</li></ul><h3 id="平均斯坦的想象实验" tabindex="-1">平均斯坦的想象实验 <a class="header-anchor" href="#平均斯坦的想象实验" aria-label="Permalink to &quot;平均斯坦的想象实验&quot;">​</a></h3><p>塔勒布在书中设计了一个经典的想象实验来说明平均斯坦的特性：</p><p>假设你从普通人群中随机挑选1000人，让他们在一个体育馆里并排站着。现在，把你所能想到的体重最重的人加入样本。假设他的体重是平均体重的3倍（约200公斤），他在总体重中所占的比例是多少？</p><p>答案是：大约0.5%。</p><p>即使你挑选了从生物学上说可能是地球上最重的人（比如500公斤），他在1000人总体重中所占的比例也只有约0.6%。如果你挑选了1万人，那么他占的比重就几乎可以忽略不计了。</p><p>这就是平均斯坦的最高法则：<strong>当你的样本量足够大时，任何个例都不会对整体产生重大影响</strong>。</p><h3 id="平均斯坦的例子" tabindex="-1">平均斯坦的例子 <a class="header-anchor" href="#平均斯坦的例子" aria-label="Permalink to &quot;平均斯坦的例子&quot;">​</a></h3><p>塔勒布列举了多个属于平均斯坦的变量：</p><p><strong>身体属性</strong></p><ul><li>身高：即使是最高的篮球运动员，他的身高也不会是平均身高的10倍</li><li>体重：如上所述，体重的极端值对总体影响有限</li><li>卡路里摄入量：任何一天的摄入量，即使暴饮暴食，也不会占年摄入量的很大部分</li></ul><p><strong>物理测量</strong></p><ul><li>温度：一天内的温度变化有明确范围</li><li>血压：正常范围内的波动</li><li>心率：即使剧烈运动，也有生理上限</li></ul><p><strong>某些职业收入</strong></p><ul><li>牙医：收入受限于每天能治疗的病人数量</li><li>面包师：必须为每位新客户烤出面包</li><li>按摩师：受限于工作时间和体力</li></ul><p><strong>其他例子</strong></p><ul><li>赌博收入（假设固定筹码）</li><li>车祸发生率</li><li>死亡率</li><li>智商（测出来的）</li></ul><h3 id="平均斯坦的统计特性" tabindex="-1">平均斯坦的统计特性 <a class="header-anchor" href="#平均斯坦的统计特性" aria-label="Permalink to &quot;平均斯坦的统计特性&quot;">​</a></h3><p>在平均斯坦中，传统的统计方法非常有效：</p><p><strong>大数定律</strong> 随着样本量的增加，样本平均值会收敛于总体平均值。这意味着我们可以通过抽样来准确估计总体特征。</p><p><strong>中心极限定理</strong> 大量独立随机变量的和近似服从正态分布（钟形曲线）。这使得我们可以用正态分布来建模和预测。</p><p><strong>可预测性</strong> 由于极端事件的影响可以忽略，我们可以相对准确地预测未来的平均值和范围。</p><h2 id="三、极端斯坦-狂野的世界" tabindex="-1">三、极端斯坦：狂野的世界 <a class="header-anchor" href="#三、极端斯坦-狂野的世界" aria-label="Permalink to &quot;三、极端斯坦：狂野的世界&quot;">​</a></h2><h3 id="定义与特征-1" tabindex="-1">定义与特征 <a class="header-anchor" href="#定义与特征-1" aria-label="Permalink to &quot;定义与特征&quot;">​</a></h3><p>极端斯坦是一个受<strong>突破性随机性</strong>支配的世界。在这个世界中，个体事件可以对整体产生不成比例的巨大影响，少数事件就能决定整体结果，极端事件虽然罕见但影响巨大。</p><p>极端斯坦的核心特征是<strong>突破性</strong>。这意味着：</p><ul><li>个体事件的影响没有明确的上限</li><li>一个极端事件可以超过所有其他事件的总和</li><li>大数定律失效或收敛极慢</li><li>单一观察值可以决定整体结果</li></ul><h3 id="极端斯坦的想象实验" tabindex="-1">极端斯坦的想象实验 <a class="header-anchor" href="#极端斯坦的想象实验" aria-label="Permalink to &quot;极端斯坦的想象实验&quot;">​</a></h3><p>让我们重复之前的想象实验，但这次考虑的是<strong>净资产</strong>而不是体重。</p><p>假设体育馆里有1000人，平均净资产为几十万美元。现在，把世界上最富有的人加入他们中间，比如比尔·盖茨（净资产约800亿美元）。</p><p>他的净资产占总资产的多少？</p><p>答案是：<strong>99.9%</strong>。</p><p>实际上，所有其他人的净资产加起来，只不过是他净资产数字的零头而已，或者仅仅是他净资产在过去一秒内的变化值。</p><p>如果某个人的体重要达到这样的比例，他需要5000万磅的体重！这在生物学上是不可能的，但在社会变量中，这种极端情况不仅可能，而且常见。</p><h3 id="极端斯坦的例子" tabindex="-1">极端斯坦的例子 <a class="header-anchor" href="#极端斯坦的例子" aria-label="Permalink to &quot;极端斯坦的例子&quot;">​</a></h3><p>塔勒布列举了更多属于极端斯坦的变量：</p><p><strong>财富与收入</strong></p><ul><li>个人财富：比尔·盖茨的财富超过许多国家的GDP</li><li>收入分布：少数人拥有大部分财富</li><li>图书版税：J.K.罗琳的收入超过其他所有英国作家的总和</li></ul><p><strong>文化与媒体</strong></p><ul><li>图书销量：《哈利·波特》系列销量数亿册，而大多数书籍销量不足千册</li><li>名人知名度：少数名人被全世界认识，大多数人默默无闻</li><li>谷歌搜索量：少数网站获得大部分流量</li><li>媒体报道：少数事件占据大部分版面</li></ul><p><strong>经济与金融</strong></p><ul><li>公司规模：少数大公司占据市场主导地位</li><li>股票持有量：少数投资者拥有大部分股票</li><li>金融市场收益：少数交易日决定大部分收益</li><li>商品价格：少数事件导致价格剧烈波动</li></ul><p><strong>自然灾害与战争</strong></p><ul><li>地震造成的损失：大地震造成的损失超过所有小地震的总和</li><li>战争死亡人数：少数战争造成大部分伤亡</li><li>恐怖袭击影响：9·11事件改变了世界格局</li></ul><p><strong>科学发现</strong></p><ul><li>学术引用：少数论文被大量引用</li><li>科学突破：少数发现改变整个学科</li></ul><h3 id="极端斯坦的统计特性" tabindex="-1">极端斯坦的统计特性 <a class="header-anchor" href="#极端斯坦的统计特性" aria-label="Permalink to &quot;极端斯坦的统计特性&quot;">​</a></h3><p>在极端斯坦中，传统的统计方法失效：</p><p><strong>大数定律失效</strong> 样本量的增加不会使平均值稳定。加入一个极端值就会彻底改变平均值。</p><p><strong>正态分布不适用</strong> 极端斯坦的数据通常服从幂律分布或分形分布，而不是正态分布。</p><p><strong>不可预测性</strong> 由于极端事件的主导作用，平均值和方差的概念失去意义，预测变得极其困难。</p><h2 id="四、两个世界的本质区别" tabindex="-1">四、两个世界的本质区别 <a class="header-anchor" href="#四、两个世界的本质区别" aria-label="Permalink to &quot;四、两个世界的本质区别&quot;">​</a></h2><h3 id="对比分析" tabindex="-1">对比分析 <a class="header-anchor" href="#对比分析" aria-label="Permalink to &quot;对比分析&quot;">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>平均斯坦</th><th>极端斯坦</th></tr></thead><tbody><tr><td>随机性类型</td><td>温和随机性</td><td>突破性随机性</td></tr><tr><td>个体影响</td><td>有限，有上限</td><td>可以无限大</td></tr><tr><td>极端事件</td><td>罕见且影响小</td><td>罕见但影响巨大</td></tr><tr><td>大数定律</td><td>有效</td><td>失效或收敛极慢</td></tr><tr><td>典型分布</td><td>正态分布（钟形曲线）</td><td>幂律分布、分形分布</td></tr><tr><td>预测难度</td><td>相对容易</td><td>极其困难</td></tr><tr><td>主导因素</td><td>集体、常规、已知</td><td>单个、意外、未知</td></tr><tr><td>典型领域</td><td>物理属性、某些职业</td><td>社会、经济、文化</td></tr></tbody></table><h3 id="关键区别-突破性" tabindex="-1">关键区别：突破性 <a class="header-anchor" href="#关键区别-突破性" aria-label="Permalink to &quot;关键区别：突破性&quot;">​</a></h3><p>两个世界的根本区别在于是否存在<strong>突破性</strong>。</p><p>在平均斯坦，存在一种&quot;阻力&quot;阻止极端值的出现。无论你怎么努力，你不可能在一天内减轻许多体重，这需要许多天、许多周甚至许多月的累积。同样，如果你是一名牙医，你永远不可能在一天内变富，但经过30年积极、勤奋、小心和日复一日的钻牙操作，你会逐渐变得富有。</p><p>在极端斯坦，这种阻力不存在。假如你从事投机行业，你可以在一分钟之内赚取或赔掉大笔财富。J.K.罗琳从一个失业的单身母亲到亿万富翁，只用了几年时间。这种突破性是平均斯坦中不可能存在的。</p><h3 id="社会变量-vs-物理变量" tabindex="-1">社会变量 vs 物理变量 <a class="header-anchor" href="#社会变量-vs-物理变量" aria-label="Permalink to &quot;社会变量 vs 物理变量&quot;">​</a></h3><p>塔勒布指出了一个重要的规律：<strong>物理变量通常属于平均斯坦，社会变量通常属于极端斯坦</strong>。</p><p><strong>为什么？</strong></p><p>物理变量受到物理定律的限制。身高、体重、温度等都有物理上限。即使是最极端的物理现象，也有其边界。</p><p>社会变量不受物理限制。银行账户里的钱只是一个数字，它可以是任何数值，不需要消耗能量。一个想法、一本书、一首歌的传播，可以无限放大，没有物理上限。</p><p>塔勒布写道：&quot;社会变量是信息化的，不是物理性的，你无法接触它们。银行账户里的钱是重要的东西，但显然不是物理性的。同样，它可以是任何数值，而不需要消耗能量。它只是一个数字！&quot;</p><h2 id="五、现代社会的迁移趋势" tabindex="-1">五、现代社会的迁移趋势 <a class="header-anchor" href="#五、现代社会的迁移趋势" aria-label="Permalink to &quot;五、现代社会的迁移趋势&quot;">​</a></h2><h3 id="从平均斯坦到极端斯坦" tabindex="-1">从平均斯坦到极端斯坦 <a class="header-anchor" href="#从平均斯坦到极端斯坦" aria-label="Permalink to &quot;从平均斯坦到极端斯坦&quot;">​</a></h3><p>塔勒布认为，现代社会越来越多地从平均斯坦迁移到极端斯坦。这种迁移是由技术进步和全球化推动的。</p><p><strong>录音技术的影响</strong></p><p>在录音技术发明之前，歌剧演员的市场是本地化的。每个地区都有自己的演员，他们无法将演唱传播到远方，其他地区的演员也无法来竞争。蛋糕被分为许多块，每个人都能分到一块。</p><p>录音技术的发明彻底改变了这一切。现在，我们可以在家听弗拉基米尔·霍洛维茨的演奏，而不是去听本地不知名音乐家的演出。霍洛维茨虽然已经去世，却让那个可怜人失业了。</p><p>结果是：少数人夺走了几乎一切，剩下的人几乎什么也得不到。</p><p><strong>印刷术的影响</strong></p><p>印刷术的发明使文字的跨国界传播成为可能。书籍可以被无限复制，作者不需要花费任何额外的精力，甚至不需要仍然健在。通常，一位作者的去世对他的职业生涯会有极大的促进。</p><p>在游吟诗人和民谣歌手时代，每个人都有自己的观众，工作有保障。而今天，少数人夺走了几乎一切。</p><p><strong>互联网的影响</strong></p><p>互联网将这一趋势推向了极致。谷歌、亚马逊、Facebook等少数公司占据了各自领域的主导地位。YouTube上少数视频获得数十亿次观看，而大多数视频几乎没有人看。</p><h3 id="全球化的影响" tabindex="-1">全球化的影响 <a class="header-anchor" href="#全球化的影响" aria-label="Permalink to &quot;全球化的影响&quot;">​</a></h3><p>全球化使美国得以专门从事创造性活动，不断创造新的理念、思想及具有突破性的产品，并且通过输出工作机会的方式，逐渐把不那么具有突破性的部分分离出去。</p><p>设计一双鞋比真正把它们做出来赚的钱要多得多——耐克、戴尔和波音只需要思考并组织和运用它们的专有技术就能赚钱，发展中国家的转包工厂则负责做那些枯燥的制造工作。</p><p>这种&quot;思维创造获得大部分报酬&quot;的世界经济框架的缺陷，就是造成了更大的不公平并提高了机会和运气的重要性的原因。</p><h3 id="战争的变化" tabindex="-1">战争的变化 <a class="header-anchor" href="#战争的变化" aria-label="Permalink to &quot;战争的变化&quot;">​</a></h3><p>在现代技术发展以前，战争曾经属于平均斯坦。如果你一次只能杀一个人，那么杀死许多人是很难的。</p><p>但今天，有了大规模杀伤性武器，只需要一个按钮，一个疯子，或者一个小错误，就能够杀光地球上所有人。</p><p>战争从平均斯坦迁移到了极端斯坦，这使得黑天鹅事件的风险大大增加。</p><h2 id="六、为什么这个区分至关重要" tabindex="-1">六、为什么这个区分至关重要？ <a class="header-anchor" href="#六、为什么这个区分至关重要" aria-label="Permalink to &quot;六、为什么这个区分至关重要？&quot;">​</a></h2><h3 id="对知识的影响" tabindex="-1">对知识的影响 <a class="header-anchor" href="#对知识的影响" aria-label="Permalink to &quot;对知识的影响&quot;">​</a></h3><p>如果你处理的是平均斯坦的数据，那么从任何样本求得平均值都是可靠的，因为它受某一单个观察值的影响很小。你可以坦然接受你的测量结果，前提是你确定这一结果来自平均斯坦。</p><p>如果你处理的是极端斯坦的数据，那么从任何样本求得平均值都是令人困扰的，因为它受某一单个观察值的影响非常大。在这个世界里，你总是会对你从数据中获得的知识表示怀疑。</p><p><strong>这是能让你区别两类不同随机性的非常简单的测试方法。</strong></p><h3 id="对预测的影响" tabindex="-1">对预测的影响 <a class="header-anchor" href="#对预测的影响" aria-label="Permalink to &quot;对预测的影响&quot;">​</a></h3><p>在平均斯坦，预测是可能的。虽然会有误差，但误差是有限的，不会导致灾难性的后果。</p><p>在极端斯坦，预测是危险的。一个错误的预测可能导致巨大的损失。更糟糕的是，我们往往不知道自己处于极端斯坦，从而用平均斯坦的方法进行预测。</p><h3 id="对风险管理的影响" tabindex="-1">对风险管理的影响 <a class="header-anchor" href="#对风险管理的影响" aria-label="Permalink to &quot;对风险管理的影响&quot;">​</a></h3><p>这是最关键的应用。2008年金融危机的根源，就在于金融工程师们用平均斯坦的工具（基于正态分布的风险模型）去管理极端斯坦的风险（金融市场的极端波动）。</p><p>塔勒布写道：&quot;他们使用错误的地图在错误的领域导航。&quot;</p><p>在平均斯坦，风险是&quot;温和&quot;的，可以用标准差、在险价值（VaR）等工具来衡量。在极端斯坦，这些工具不仅无效，而且危险，因为它们给人一种虚假的安全感。</p><h3 id="对决策的影响" tabindex="-1">对决策的影响 <a class="header-anchor" href="#对决策的影响" aria-label="Permalink to &quot;对决策的影响&quot;">​</a></h3><p>在平均斯坦，我们可以依赖历史数据和统计模型来做决策。过去的数据对未来有参考价值。</p><p>在极端斯坦，历史数据可能误导我们。过去没有发生过的事件，不代表未来不会发生。事实上，最重大的事件往往是历史上从未发生过的。</p><h2 id="七、实际案例分析" tabindex="-1">七、实际案例分析 <a class="header-anchor" href="#七、实际案例分析" aria-label="Permalink to &quot;七、实际案例分析&quot;">​</a></h2><h3 id="案例一-出版业的不公平" tabindex="-1">案例一：出版业的不公平 <a class="header-anchor" href="#案例一-出版业的不公平" aria-label="Permalink to &quot;案例一：出版业的不公平&quot;">​</a></h3><p>塔勒布在书中详细分析了出版业的极端斯坦特性。</p><p>在法国，大文学出版商只会接受新作家作品的千分之一。《纽约客》每天就要退回近100份手稿。想想有多少演员从未通过试镜，但假如他们有足以改变生活的运气，他们本来能够演得很好。</p><p>结果是：极少数畅销书占据了大部分销量。在美国出版业，分配比例更可能是97/20（也就是97%的图书销量来自20%的作者）。如果只看非虚构类作品，情况更严重（8000种图书中的20种占据一半的销量）。</p><p>这与平均斯坦的直觉完全相反。在平均斯坦，我们预期销量会相对均匀地分布。但在极端斯坦，赢家通吃。</p><h3 id="案例二-1987年股市崩盘" tabindex="-1">案例二：1987年股市崩盘 <a class="header-anchor" href="#案例二-1987年股市崩盘" aria-label="Permalink to &quot;案例二：1987年股市崩盘&quot;">​</a></h3><p>1987年10月19日，美国股市发生了历史上最大的单日跌幅：道琼斯指数下跌22.6%。</p><p>按照正态分布的假设，这种幅度的下跌发生的概率是多少？</p><p>根据标准的风险模型，这种事件发生的概率是10的几十次方分之一——在宇宙的历史中都不应该发生一次。</p><p>但它确实发生了。</p><p>这就是用平均斯坦的工具分析极端斯坦数据的后果。模型告诉我们这种事件&quot;不可能&quot;发生，所以它没有为我们的投资组合提供任何保护。</p><h3 id="案例三-职业选择的突破性与非突破性" tabindex="-1">案例三：职业选择的突破性与非突破性 <a class="header-anchor" href="#案例三-职业选择的突破性与非突破性" aria-label="Permalink to &quot;案例三：职业选择的突破性与非突破性&quot;">​</a></h3><p>塔勒布在书中讨论了一个22岁学生给他的建议：找一份&quot;报酬具有突破性&quot;的职业。</p><p><strong>非突破性职业</strong>：牙医、咨询师、按摩师。这些职业的收入受限于在既定时间内服务的病人或客户的最大数量。不论报酬多高，收入总是受到限制。</p><p><strong>突破性职业</strong>：作家、电影演员、创业者。这些职业如果干得好，能让产出（以及收入）十倍、百倍地增长，同时几乎不需要付出额外的努力。</p><p>这个建议本身是好是坏？塔勒布认为，这取决于运气。突破性职业只有在你成功的时候才对你有利。这样的职业竞争更激烈，不平均性和不确定性更高，努力和回报之间的差异巨大。</p><p>关键是理解：你选择的职业属于哪个斯坦？</p><h2 id="八、灰天鹅-可预测的黑天鹅" tabindex="-1">八、灰天鹅：可预测的黑天鹅 <a class="header-anchor" href="#八、灰天鹅-可预测的黑天鹅" aria-label="Permalink to &quot;八、灰天鹅：可预测的黑天鹅&quot;">​</a></h2><h3 id="概念介绍" tabindex="-1">概念介绍 <a class="header-anchor" href="#概念介绍" aria-label="Permalink to &quot;概念介绍&quot;">​</a></h3><p>塔勒布在书中提出了一个中间概念：<strong>灰天鹅（Gray Swan）</strong>。</p><p>灰天鹅是那些很少发生、很有影响，但某种程度上是可预测的事件，尤其对那些有准备并且有办法去理解它们的人。它们是黑天鹅的近亲，在某种程度上是可以用科学方法理解的。</p><h3 id="与黑天鹅的区别" tabindex="-1">与黑天鹅的区别 <a class="header-anchor" href="#与黑天鹅的区别" aria-label="Permalink to &quot;与黑天鹅的区别&quot;">​</a></h3><table tabindex="0"><thead><tr><th>黑天鹅</th><th>灰天鹅</th></tr></thead><tbody><tr><td>完全不可预测</td><td>罕见但可预测</td></tr><tr><td>超出所有预期</td><td>在预测范围内</td></tr><tr><td>事后才能解释</td><td>有准备的人可以预见</td></tr><tr><td>完全出乎意料</td><td>可能性虽低但存在</td></tr></tbody></table><h3 id="例子" tabindex="-1">例子 <a class="header-anchor" href="#例子" aria-label="Permalink to &quot;例子&quot;">​</a></h3><ul><li>大地震：我们知道某个地区可能发生大地震，但不知道具体时间</li><li>金融危机：我们知道泡沫会破裂，但不知道何时</li><li>流行病：我们知道大流行会发生，但不知道具体病毒</li></ul><p>了解灰天鹅的发生频率会降低你的惊奇感，但并不能消除风险。</p><h2 id="九、本章总结" tabindex="-1">九、本章总结 <a class="header-anchor" href="#九、本章总结" aria-label="Permalink to &quot;九、本章总结&quot;">​</a></h2><h3 id="核心要点回顾" tabindex="-1">核心要点回顾 <a class="header-anchor" href="#核心要点回顾" aria-label="Permalink to &quot;核心要点回顾&quot;">​</a></h3><ol><li><strong>两个世界的划分</strong>：平均斯坦（温和随机性）和极端斯坦（突破性随机性）。</li><li><strong>平均斯坦的特征</strong>：个体影响有限，极端事件罕见且影响小，传统统计方法有效。</li><li><strong>极端斯坦的特征</strong>：个体影响可以巨大，极端事件主导结果，传统统计方法失效。</li><li><strong>现代社会的迁移</strong>：技术进步和全球化使社会越来越多地从平均斯坦迁移到极端斯坦。</li><li><strong>区分的意义</strong>：使用正确的工具理解世界，避免用平均斯坦的方法处理极端斯坦的风险。</li></ol><h3 id="关键术语" tabindex="-1">关键术语 <a class="header-anchor" href="#关键术语" aria-label="Permalink to &quot;关键术语&quot;">​</a></h3><ul><li><strong>平均斯坦（Mediocristan）</strong>：个体事件影响有限的世界，受温和随机性支配。</li><li><strong>极端斯坦（Extremistan）</strong>：个体事件可以产生不成比例影响的世界，受突破性随机性支配。</li><li><strong>突破性</strong>：不受阻力限制的增长或影响能力。</li><li><strong>灰天鹅</strong>：罕见但有影响、某种程度上可预测的事件。</li><li><strong>幂律分布</strong>：描述极端斯坦现象的统计分布。</li><li><strong>赢家通吃</strong>：少数赢家获得大部分收益的现象。</li></ul><h3 id="实用建议" tabindex="-1">实用建议 <a class="header-anchor" href="#实用建议" aria-label="Permalink to &quot;实用建议&quot;">​</a></h3><ol><li><strong>识别你所在的斯坦</strong>：分析你面临的问题属于平均斯坦还是极端斯坦。</li><li><strong>选择正确的工具</strong>：不要用正态分布分析极端斯坦的数据。</li><li><strong>警惕虚假安全感</strong>：标准差、在险价值等工具在极端斯坦中可能误导你。</li><li><strong>为极端事件做准备</strong>：在极端斯坦中，最重大的事件往往是历史上从未发生过的。</li><li><strong>职业选择</strong>：理解突破性职业的风险和回报，做出明智的选择。</li></ol><h3 id="延伸思考" tabindex="-1">延伸思考 <a class="header-anchor" href="#延伸思考" aria-label="Permalink to &quot;延伸思考&quot;">​</a></h3><ul><li>你的工作或行业属于平均斯坦还是极端斯坦？</li><li>你使用的分析工具是否适合你所面对的问题？</li><li>如何在不放弃预测的情况下，为不可预测的事件做好准备？</li><li>在极端斯坦的世界中，公平和效率如何平衡？</li></ul><hr><p><em>本文基于《黑天鹅：如何应对不可预知的未来》整理，作者：纳西姆·尼古拉斯·塔勒布</em></p><p><strong>系列导航：</strong></p><ul><li><a href="/posts/black-swan-part1.html">第一篇：引言与核心概念</a></li><li>第二篇：两个世界——平均斯坦与极端斯坦（本文）</li><li><a href="/posts/black-swan-part3.html">第三篇：认知陷阱——为什么我们看不见黑天鹅</a></li><li><a href="/posts/black-swan-part4.html">第四篇：专家的幻觉与预测的徒劳</a></li><li><a href="/posts/black-swan-part5.html">第五篇：反脆弱——从不确定性中获益</a></li><li><a href="/posts/black-swan-part6.html">第六篇：实用生存法则与对现代社会的批判</a></li></ul>',149)])])}const c=t(i,[["render",e]]);export{g as __pageData,c as default};
